### WotLK (3.3.5) Packet Specifications

#### 1. SMSG_MAIL_LIST_RESULT (Opcode: 0x023B)
**Purpose:** Server sends list of mails in mailbox

```
struct Mail {
    u16 size;
    u32 message_id;
    MailType message_type;

    [Conditional - depends on message_type]:
    if (message_type == NORMAL)
        Guid sender;
    else if (message_type == CREATURE || message_type == GAMEOBJECT)
        u32 sender_id;
    else if (message_type == AUCTION)
        u32 auction_id;
    else if (message_type == ITEM)
        Item item;

    Gold cash_on_delivery;
    u32 unknown;
    u32 stationery;
    Gold money;
    u32 flags;
    f32 expiration_time;
    u32 mail_template_id;
    CString subject;
    CString message;
    u8 amount_of_items;
    MailListItem[amount_of_items] items;
}

struct MailListItem {
    u8 item_index;
    u32 low_guid;
    Item item;                           // u32 item ID
    MailListItemEnchant[7] enchants;
    u32 item_random_property_id;
    u32 item_suffix_factor;
    u8 item_amount;
    u32 charges;
    u32 max_durability;
    u32 durability;
    u8 unknown;
}

struct MailListItemEnchant {
    u32 charges;
    u32 duration;
    u32 enchant_id;
}

smsg SMSG_MAIL_LIST_RESULT = 0x023B {
    u32 real_mail_amount;        // AzerothCore: displays warning if realCount > mailsCount
    u8 amount_of_mails;
    Mail[amount_of_mails] mails;
}
```

#### 2. CMSG_SEND_MAIL (Opcode: 0x0238)
**Purpose:** Client sends mail

```
