    Guid item;
    u8 slot;
}

cmsg CMSG_SEND_MAIL = 0x0238 {
    Guid mailbox;
    CString receiver;
    CString subject;
    CString body;
    u32 unknown1;               // cmangos: stationery?
    u32 unknown2;               // cmangos: 0x00000000
    u8 amount_of_items;
    MailItem[amount_of_items] items;
    Gold money;
    u32 cash_on_delivery_amount;
    u32 unknown3;               // mangosone: const 0
    u32 unknown4;               // mangosone: const 0
}
```
**Applies to:** TBC 2.4.3 and WotLK 3.3.5

#### 3. CMSG_GET_MAIL_LIST (Opcode: 0x023A)
**Purpose:** Client requests mail list

