  handleGroupDestroyed,
  handleGroupUninvite,
  handleGroupDeclineMsg,
  handleRandomRoll,
  handleUpdateObject,
  handleCompressedUpdateObject,
  handleDestroyObject,
  handleCreatureQueryResponse,
  handleGameObjectQueryResponse,
  handlePartyMemberStatsMsg,
  handleContactList,
  handleFriendStatus,
  handleGuildRoster,
  handleGuildQueryResponse,
  handleGuildEvent,
  handleDuelRequested,
