402→export function handleUpdateObject(conn: WorldConn, r: PacketReader): void {
403→  const entries = parseUpdateObject(r);
404→  for (const entry of entries) {
405→    switch (entry.type) {
406→      case "create": {
407→        const { _changed: _co, ...objFields } = extractObjectFields(
408→          entry.fields,
409→        );
410→        let extraFields: Record<string, unknown> = {};
411→        if (
412→          entry.objectType === ObjectType.UNIT ||
413→          entry.objectType === ObjectType.PLAYER
414→        ) {
415→          const { _changed: _cu, ...rest } = extractUnitFields(entry.fields);
416→          extraFields = rest;
417→        } else if (entry.objectType === ObjectType.GAMEOBJECT) {
418→          const { _changed: _cg, ...rest } = extractGameObjectFields(
419→            entry.fields,
420→          );
421→          extraFields = rest;
422→        }
423→        const cachedName = lookupCachedName(
424→          conn,
425→          entry.guid,
426→          entry.objectType,
427→          objFields.entry,
428→        );
429→        conn.entityStore.create(entry.guid, entry.objectType, {
430→          ...objFields,
431→          ...extraFields,
432→          ...(cachedName ? { name: cachedName } : {}),
433→          ...(entry.position ? { position: entry.position } : {}),
434→          rawFields: new Map(entry.fields),
435→        } as any);
436→        if (!cachedName) {
437→          queryEntityName(conn, entry.guid, entry.objectType, objFields.entry);
438→        }
439→        break;
440→      }
441→      case "values": {
442→        const entity = conn.entityStore.get(entry.guid);
443→        if (!entity) break;
444→        const objFields = extractObjectFields(entry.fields, entity.rawFields);
445→        let extraFields: Record<string, unknown> = {};
446→        if (
447→          entity.objectType === ObjectType.UNIT ||
448→          entity.objectType === ObjectType.PLAYER
449→        ) {
450→          extraFields = extractUnitFields(entry.fields, entity.rawFields);
451→        } else if (entity.objectType === ObjectType.GAMEOBJECT) {
452→          extraFields = extractGameObjectFields(entry.fields);
453→        }
454→        const allChanged = [
455→          ...(objFields._changed || []),
456→          ...((extraFields as any)._changed || []),
457→        ];
458→        const merged: Record<string, unknown> = {};
459→        for (const key of allChanged) {
460→          if (key in extraFields) merged[key] = (extraFields as any)[key];
461→          else if (key in objFields) merged[key] = (objFields as any)[key];
462→        }
463→        conn.entityStore.update(entry.guid, merged);
464→        for (const [k, v] of entry.fields) {
465→          const existing = conn.entityStore.get(entry.guid);
466→          if (existing) existing.rawFields.set(k, v);
467→        }
468→        break;
469→      }
470→      case "movement": {
471→        conn.entityStore.setPosition(entry.guid, entry.position);
472→        break;
473→      }
474→      case "outOfRange": {
475→        for (const guid of entry.guids) conn.entityStore.destroy(guid);
476→        break;
477→      }
478→      case "nearObjects": {
479→        break;
480→      }
481→    }
482→  }
483→}
