624→      area: contact.area ?? 0,
625→      level: contact.level ?? 0,
626→      playerClass: contact.playerClass ?? 0,
627→    });
628→    if (!name) ensureNameQuery(conn, contact.guid);
629→  }
630→  conn.friendStore.set(friends);
631→
632→  const ignored: IgnoreEntry[] = [];
633→  for (const contact of list.contacts) {
634→    if (!(contact.flags & SocialFlag.IGNORED)) continue;
635→    const guidLow = Number(contact.guid & 0xffffffffn);
636→    const name = conn.nameCache.get(guidLow) ?? "";
637→    ignored.push({ guid: contact.guid, name });
638→    if (!name) ensureNameQuery(conn, contact.guid);
639→  }
640→  conn.ignoreStore.set(ignored);
641→}
642→
643→export function handleFriendStatus(conn: WorldConn, r: PacketReader): void {
644→  const packet = parseFriendStatus(r);
645→  const guidLow = Number(packet.guid & 0xffffffffn);
646→
647→  switch (packet.result) {
648→    case FriendResult.ADDED_ONLINE:
649→    case FriendResult.ADDED_OFFLINE: {
650→      const name = conn.nameCache.get(guidLow) ?? "";
651→      conn.friendStore.add({
652→        guid: packet.guid,
653→        name,
654→        note: packet.note ?? "",
655→        status: packet.status ?? 0,
656→        area: packet.area ?? 0,
657→        level: packet.level ?? 0,
658→        playerClass: packet.playerClass ?? 0,
659→      });
660→      if (!name) ensureNameQuery(conn, packet.guid);
661→      break;
662→    }
663→    case FriendResult.ONLINE:
664→      conn.friendStore.update(packet.guid, {
665→        status: packet.status ?? FriendStatus.ONLINE,
666→        area: packet.area ?? 0,
667→        level: packet.level ?? 0,
668→        playerClass: packet.playerClass ?? 0,
669→      });
670→      break;
671→    case FriendResult.OFFLINE:
672→      conn.friendStore.update(packet.guid, { status: FriendStatus.OFFLINE });
673→      break;
674→    case FriendResult.REMOVED:
675→      conn.friendStore.remove(packet.guid);
676→      break;
677→    case FriendResult.IGNORE_ADDED: {
678→      const name = conn.nameCache.get(guidLow) ?? "";
679→      conn.ignoreStore.add({ guid: packet.guid, name });
680→      if (!name) ensureNameQuery(conn, packet.guid);
681→      break;
682→    }
683→    case FriendResult.IGNORE_REMOVED:
684→      conn.ignoreStore.remove(packet.guid);
685→      break;
686→    case FriendResult.IGNORE_FULL:
687→    case FriendResult.IGNORE_SELF:
688→    case FriendResult.IGNORE_NOT_FOUND:
689→    case FriendResult.IGNORE_ALREADY:
690→    case FriendResult.IGNORE_AMBIGUOUS: {
691→      const name = conn.nameCache.get(guidLow) ?? `guid:${guidLow}`;
692→      conn.onIgnoreEvent?.({
693→        type: "ignore-error",
694→        result: packet.result,
695→        name,
696→      });
697→      break;
698→    }
699→    default: {
700→      const name = conn.nameCache.get(guidLow) ?? `guid:${guidLow}`;
701→      conn.onFriendEvent?.({
702→        type: "friend-error",
703→        result: packet.result,
704→        name,
705→      });
706→      break;
707→    }
708→  }
709→}
710→
711→export function handleGuildRoster(conn: WorldConn, r: PacketReader): void {
712→  const raw = parseGuildRoster(r);
713→  const members: GuildMember[] = raw.members.map((m) => ({ ...m }));
714→  conn.guildStore.setRoster(raw.motd, raw.guildInfo, members);
715→}
716→
717→export function handleGuildQueryResponse(
718→  conn: WorldConn,
719→  r: PacketReader,
720→): void {
721→  const result = parseGuildQueryResponse(r);
722→  conn.guildStore.setGuildMeta(result.name, result.rankNames);
723→}
724→
725→export function handleGuildEvent(conn: WorldConn, r: PacketReader): void {
726→  const raw = parseGuildEvent(r);
727→  const p = raw.params;
728→  switch (raw.eventType) {
729→    case GuildEventCode.PROMOTION:
730→      conn.onGuildEvent?.({
731→        type: "promotion",
732→        officer: p[0] ?? "",
733→        member: p[1] ?? "",
734→        rank: p[2] ?? "",
735→      });
736→      break;
737→    case GuildEventCode.DEMOTION:
738→      conn.onGuildEvent?.({
739→        type: "demotion",
740→        officer: p[0] ?? "",
741→        member: p[1] ?? "",
742→        rank: p[2] ?? "",
743→      });
744→      break;
745→    case GuildEventCode.MOTD:
746→      conn.onGuildEvent?.({ type: "motd", text: p[0] ?? "" });
747→      break;
748→    case GuildEventCode.JOINED:
749→      conn.onGuildEvent?.({ type: "joined", name: p[0] ?? "" });
750→      break;
751→    case GuildEventCode.LEFT:
752→      conn.onGuildEvent?.({ type: "left", name: p[0] ?? "" });
753→      break;
754→    case GuildEventCode.REMOVED:
755→      conn.onGuildEvent?.({
756→        type: "removed",
757→        member: p[0] ?? "",
758→        officer: p[1] ?? "",
759→      });
760→      break;
761→    case GuildEventCode.LEADER_IS:
762→      conn.onGuildEvent?.({ type: "leader_is", name: p[0] ?? "" });
763→      break;
764→    case GuildEventCode.LEADER_CHANGED:
