332→export async function dispatchCommand(
333→  cmd: IpcCommand,
334→  handle: WorldHandle,
335→  events: RingBuffer<EventEntry>,
336→  socket: IpcSocket,
337→  cleanup: () => void,
338→): Promise<boolean> {
339→  switch (cmd.type) {
340→    case "chat": {
341→      handle.sendInCurrentMode(cmd.message);
342→      const mode = handle.getLastChatMode();
343→      const label =
344→        mode.type === "whisper"
345→          ? `WHISPER ${mode.target}`
346→          : mode.type === "channel"
347→            ? `CHANNEL ${mode.channel}`
348→            : mode.type.toUpperCase();
349→      writeLines(socket, [`OK ${label}`]);
350→      return false;
351→    }
352→    case "say":
353→      handle.sendSay(cmd.message);
354→      writeLines(socket, ["OK"]);
355→      return false;
356→    case "yell":
357→      handle.sendYell(cmd.message);
358→      writeLines(socket, ["OK"]);
359→      return false;
360→    case "guild":
361→      handle.sendGuild(cmd.message);
362→      writeLines(socket, ["OK"]);
363→      return false;
364→    case "party":
365→      handle.sendParty(cmd.message);
366→      writeLines(socket, ["OK"]);
367→      return false;
368→    case "emote":
369→      handle.sendEmote(cmd.message);
370→      writeLines(socket, ["OK"]);
371→      return false;
372→    case "dnd":
373→      handle.sendDnd(cmd.message);
374→      writeLines(socket, ["OK"]);
375→      return false;
376→    case "afk":
377→      handle.sendAfk(cmd.message);
378→      writeLines(socket, ["OK"]);
379→      return false;
380→    case "whisper":
381→      handle.sendWhisper(cmd.target, cmd.message);
382→      writeLines(socket, ["OK"]);
383→      return false;
384→    case "roll":
385→      handle.sendRoll(cmd.min, cmd.max);
386→      writeLines(socket, ["OK"]);
387→      return false;
388→    case "read":
389→      writeLines(socket, drainText(events));
390→      return false;
391→    case "read_json":
392→      writeLines(socket, drainJson(events));
393→      return false;
394→    case "read_wait": {
395→      const start = events.writePos;
396→      await new Promise<void>((resolve) => {
397→        setTimeout(() => {
398→          writeLines(socket, sliceText(events, start));
399→          resolve();
400→        }, cmd.ms);
401→      });
402→      return false;
403→    }
404→    case "read_wait_json": {
405→      const start = events.writePos;
406→      await new Promise<void>((resolve) => {
407→        setTimeout(() => {
408→          writeLines(socket, sliceJson(events, start));
409→          resolve();
410→        }, cmd.ms);
411→      });
412→      return false;
413→    }
414→    case "stop":
415→      writeLines(socket, ["OK"]);
416→      cleanup();
417→      return true;
418→    case "status":
419→      writeLines(socket, ["CONNECTED"]);
420→      return false;
421→    case "who": {
422→      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
423→      writeLines(socket, formatWhoResults(results).split("\n"));
424→      return false;
425→    }
426→    case "who_json": {
427→      const results = await handle.who(cmd.filter ? { name: cmd.filter } : {});
428→      writeLines(socket, [formatWhoResultsJson(results)]);
429→      return false;
430→    }
431→    case "invite":
432→      handle.invite(cmd.target);
433→      writeLines(socket, ["OK"]);
434→      return false;
435→    case "kick":
436→      handle.uninvite(cmd.target);
437→      writeLines(socket, ["OK"]);
438→      return false;
439→    case "leave":
440→      handle.leaveGroup();
441→      writeLines(socket, ["OK"]);
442→      return false;
443→    case "leader":
444→      handle.setLeader(cmd.target);
445→      writeLines(socket, ["OK"]);
446→      return false;
447→    case "accept":
448→      handle.acceptInvite();
449→      writeLines(socket, ["OK"]);
450→      return false;
451→    case "decline":
452→      handle.declineInvite();
453→      writeLines(socket, ["OK"]);
454→      return false;
455→    case "nearby": {
456→      const entities = handle.getNearbyEntities();
457→      writeLines(socket, entities.map(formatNearbyLine));
458→      return false;
459→    }
460→    case "nearby_json": {
461→      const entities = handle.getNearbyEntities();
462→      writeLines(
463→        socket,
464→        entities.map((e) => JSON.stringify(formatNearbyObj(e))),
465→      );
466→      return false;
467→    }
468→    case "friends": {
469→      const friends = handle.getFriends();
470→      writeLines(socket, formatFriendList(friends).split("\n"));
471→      return false;
472→    }
473→    case "friends_json": {
474→      const friends = handle.getFriends();
475→      writeLines(socket, [formatFriendListJson(friends)]);
476→      return false;
477→    }
478→    case "add_friend":
479→      handle.addFriend(cmd.target);
480→      writeLines(socket, ["OK"]);
481→      return false;
482→    case "del_friend":
483→      handle.removeFriend(cmd.target);
484→      writeLines(socket, ["OK"]);
485→      return false;
486→    case "ignored": {
487→      const ignored = handle.getIgnored();
488→      writeLines(socket, formatIgnoreList(ignored).split("\n"));
489→      return false;
490→    }
491→    case "ignored_json": {
492→      const ignored = handle.getIgnored();
493→      writeLines(socket, [formatIgnoreListJson(ignored)]);
494→      return false;
495→    }
496→    case "add_ignore":
497→      handle.addIgnore(cmd.target);
498→      writeLines(socket, ["OK"]);
499→      return false;
500→    case "del_ignore":
501→      handle.removeIgnore(cmd.target);
502→      writeLines(socket, ["OK"]);
503→      return false;
504→    case "join_channel":
505→      handle.joinChannel(cmd.channel, cmd.password);
506→      writeLines(socket, ["OK"]);
507→      return false;
508→    case "leave_channel":
509→      handle.leaveChannel(cmd.channel);
510→      writeLines(socket, ["OK"]);
511→      return false;
512→    case "guild_roster": {
513→      const roster = await handle.requestGuildRoster();
514→      if (roster) {
515→        writeLines(socket, formatGuildRoster(roster).split("\n"));
516→      } else {
517→        writeLines(socket, ["[guild] No guild roster available"]);
518→      }
519→      return false;
520→    }
521→    case "guild_roster_json": {
522→      const roster = await handle.requestGuildRoster();
523→      if (roster) {
524→        writeLines(socket, [formatGuildRosterJson(roster)]);
525→      } else {
526→        writeLines(socket, [
527→          JSON.stringify({ type: "GUILD_ROSTER", members: [] }),
528→        ]);
529→      }
530→      return false;
531→    }
532→    case "guild_invite":
533→      handle.guildInvite(cmd.target);
534→      writeLines(socket, ["OK"]);
535→      return false;
536→    case "guild_kick":
537→      handle.guildRemove(cmd.target);
538→      writeLines(socket, ["OK"]);
539→      return false;
540→    case "guild_leave":
541→      handle.guildLeave();
542→      writeLines(socket, ["OK"]);
543→      return false;
544→    case "guild_promote":
545→      handle.guildPromote(cmd.target);
546→      writeLines(socket, ["OK"]);
547→      return false;
548→    case "guild_demote":
549→      handle.guildDemote(cmd.target);
550→      writeLines(socket, ["OK"]);
551→      return false;
552→    case "guild_leader":
553→      handle.guildLeader(cmd.target);
554→      writeLines(socket, ["OK"]);
555→      return false;
556→    case "guild_motd":
557→      handle.guildMotd(cmd.message);
558→      writeLines(socket, ["OK"]);
559→      return false;
560→    case "guild_accept":
561→      handle.acceptGuildInvite();
562→      writeLines(socket, ["OK"]);
563→      return false;
564→    case "guild_decline":
565→      handle.declineGuildInvite();
566→      writeLines(socket, ["OK"]);
567→      return false;
568→    case "unimplemented":
569→      writeLines(socket, [`UNIMPLEMENTED ${cmd.feature}`]);
570→      return false;
571→  }
572→}
