574→function objectTypeName(type: ObjectType): string {
575→  switch (type) {
576→    case ObjectType.UNIT:
577→      return "NPC";
578→    case ObjectType.PLAYER:
579→      return "Player";
580→    default:
581→      return `type ${type}`;
582→  }
583→}
584→
585→function formatNearbyLine(entity: Entity): string {
586→  if (
587→    entity.objectType === ObjectType.UNIT ||
588→    entity.objectType === ObjectType.PLAYER
589→  ) {
590→    const unit = entity as UnitEntity;
591→    const name = entity.name ?? "Unknown";
592→    const kind = objectTypeName(entity.objectType);
593→    const level = unit.level > 0 ? `, level ${unit.level}` : "";
594→    const hp = `HP ${unit.health}/${unit.maxHealth}`;
595→    const pos = entity.position
596→      ? ` at ${entity.position.x.toFixed(2)}, ${entity.position.y.toFixed(2)}, ${entity.position.z.toFixed(2)}`
597→      : "";
598→    return `${name} (${kind}${level}) ${hp}${pos}`;
599→  }
600→  if (entity.objectType === ObjectType.GAMEOBJECT) {
601→    const name = entity.name ?? "Unknown";
602→    const pos = entity.position
603→      ? ` at ${entity.position.x.toFixed(2)}, ${entity.position.y.toFixed(2)}, ${entity.position.z.toFixed(2)}`
604→      : "";
605→    return `${name} (GameObject)${pos}`;
606→  }
607→  return `Entity 0x${entity.guid.toString(16)} (${objectTypeName(entity.objectType)})`;
608→}
609→
610→function objectTypeString(type: ObjectType): string {
611→  switch (type) {
612→    case ObjectType.UNIT:
613→      return "unit";
614→    case ObjectType.PLAYER:
615→      return "player";
616→    case ObjectType.GAMEOBJECT:
617→      return "gameobject";
618→    default:
619→      return "object";
620→  }
621→}
622→
623→function formatNearbyObj(entity: Entity): Record<string, unknown> {
624→  const obj: Record<string, unknown> = {
625→    guid: `0x${entity.guid.toString(16)}`,
626→    type: objectTypeString(entity.objectType),
627→    name: entity.name,
628→  };
629→  if (
630→    entity.objectType === ObjectType.UNIT ||
631→    entity.objectType === ObjectType.PLAYER
632→  ) {
633→    const unit = entity as UnitEntity;
634→    obj["level"] = unit.level;
635→    obj["health"] = unit.health;
636→    obj["maxHealth"] = unit.maxHealth;
637→  }
638→  if (entity.objectType === ObjectType.GAMEOBJECT) {
639→    obj["gameObjectType"] = (entity as GameObjectEntity).gameObjectType;
640→  }
641→  if (entity.position) {
642→    obj["x"] = entity.position.x;
643→    obj["y"] = entity.position.y;
644→    obj["z"] = entity.position.z;
645→  }
646→  return obj;
647→}
