649→function formatGroupEventObj(event: GroupEvent): Record<string, unknown> {
650→  switch (event.type) {
651→    case "invite_received":
652→      return { type: "GROUP_INVITE", from: event.from };
653→    case "command_result":
654→      return {
655→        type: "GROUP_COMMAND_RESULT",
656→        operation: event.operation,
657→        target: event.target,
658→        result: event.result,
659→      };
660→    case "leader_changed":
661→      return { type: "GROUP_LEADER_CHANGED", name: event.name };
662→    case "group_destroyed":
663→      return { type: "GROUP_DESTROYED" };
664→    case "kicked":
665→      return { type: "GROUP_KICKED" };
666→    case "invite_declined":
667→      return { type: "GROUP_INVITE_DECLINED", name: event.name };
668→    case "group_list":
669→      return {
670→        type: "GROUP_LIST",
671→        members: event.members.map((m) => ({
672→          name: m.name,
673→          online: m.online,
674→        })),
675→        leader: event.leader,
676→      };
677→    case "member_stats":
678→      return {
679→        type: "PARTY_MEMBER_STATS",
680→        guidLow: event.guidLow,
681→        online: event.online,
682→        hp: event.hp,
683→        maxHp: event.maxHp,
684→        level: event.level,
685→      };
686→  }
687→}
