213→    handle.onMessage((msg) => {
214→      if (msg.type === ChatType.WHISPER) state.lastWhisperFrom = msg.sender;
215→      const line = formatMessage(msg);
216→      write(interactive ? `\r\x1b[K${line}\n` : line + "\n");
