230→      if (!line) return;
231→      write(interactive ? `\r\x1b[K${line}\n` : line + "\n");
232→      if (interactive) rl.prompt(true);
233→    });
234→
235→    const rl = createInterface({
236→      input: opts.input ?? process.stdin,
237→      output: interactive ? process.stdout : undefined,
238→      prompt: interactive ? formatPrompt(handle.getLastChatMode()) : "",
239→      terminal: interactive,
240→    });
241→
242→    if (interactive) rl.prompt();
243→
244→    rl.on("line", async (input) => {
245→      try {
246→        if (await executeCommand(state, parseCommand(input.trim()))) {
247→          handle.close();
248→          rl.close();
249→          resolve();
250→          return;
251→        }
252→      } catch (err) {
253→        const msg = err instanceof Error ? err.message : String(err);
254→        write(formatError(msg) + "\n");
255→      }
256→      if (interactive) {
257→        rl.setPrompt(formatPrompt(handle.getLastChatMode()));
258→        rl.prompt();
259→      }
260→    });
261→
262→    rl.on("SIGINT", () => {
263→      handle.close();
264→      rl.close();
265→    });
266→
267→    rl.on("close", () => {
268→      handle.close();
269→      resolve();
270→    });
271→
272→    handle.closed.then(() => rl.close());
273→  });
274→}
