  const result = parseSendMailResult(r);
  if (result.action === MailAction.SEND) {
    const err = formatMailResultError(result.result);
    if (err) {
      conn.onMessage?.({
        type: ChatType.SYSTEM,
        sender: "",
        message: `[mail] ${err}`,
        origin: "mail",
