# In-Game Mail Implementation Plan

> **For Claude:** REQUIRED SUB-SKILL: Use superpowers:executing-plans to implement this plan task-by-task.

**Goal:** Add text-only in-game mail support — list, read, send, delete via /mail commands.

**Architecture:** Protocol parsing in `src/wow/protocol/mail.ts`, handlers in `world-handlers.ts`, state on WorldConn, commands in both TUI and daemon paths. Follows the existing guild roster request/response pattern.

**Tech Stack:** TypeScript, Bun, PacketReader/PacketWriter

---

### Task 1: Mail Protocol Types and Parse/Build Functions

**Files:**
- Create: `src/wow/protocol/mail.ts`
- Create: `src/wow/protocol/mail.test.ts`

**Step 1: Write failing tests for all parse/build functions**

```typescript
// src/wow/protocol/mail.test.ts
import { test, expect, describe } from "bun:test";
import { PacketReader, PacketWriter } from "wow/protocol/packet";
import {
  MailMessageType,
  MailCheckMask,
  MailAction,
  MailResult,
  parseShowMailbox,
  parseMailListResult,
  parseSendMailResult,
  buildGetMailList,
  buildSendMail,
  buildMailDelete,
  buildMailMarkAsRead,
  formatMailResultError,
  type MailEntry,
} from "wow/protocol/mail";

describe("parseShowMailbox", () => {
  test("reads mailbox guid", () => {
    const w = new PacketWriter();
    w.uint64LE(0x1234n);
    const result = parseShowMailbox(new PacketReader(w.finish()));
    expect(result).toBe(0x1234n);
  });

  test("consumes all bytes", () => {
    const w = new PacketWriter();
    w.uint64LE(99n);
    const r = new PacketReader(w.finish());
    parseShowMailbox(r);
    expect(r.remaining).toBe(0);
  });
});

describe("buildGetMailList", () => {
  test("writes mailbox guid as u64 LE", () => {
    const body = buildGetMailList(0xABCDn);
    const r = new PacketReader(body);
    expect(r.uint64LE()).toBe(0xABCDn);
    expect(r.remaining).toBe(0);
  });
});

describe("buildSendMail", () => {
  test("writes mailbox guid, receiver, subject, body, and zeroed fields", () => {
    const body = buildSendMail(100n, "Thrall", "Hello", "How are you?");
    const r = new PacketReader(body);
    expect(r.uint64LE()).toBe(100n);
    expect(r.cString()).toBe("Thrall");
    expect(r.cString()).toBe("Hello");
    expect(r.cString()).toBe("How are you?");
    expect(r.uint32LE()).toBe(0);
    expect(r.uint32LE()).toBe(0);
    expect(r.uint8()).toBe(0);
    expect(r.uint32LE()).toBe(0);
    expect(r.uint32LE()).toBe(0);
    expect(r.uint32LE()).toBe(0);
    expect(r.uint32LE()).toBe(0);
    expect(r.remaining).toBe(0);
  });

  test("handles empty subject and body", () => {
    const body = buildSendMail(1n, "Jaina", "", "");
    const r = new PacketReader(body);
    r.uint64LE();
    expect(r.cString()).toBe("Jaina");
    expect(r.cString()).toBe("");
    expect(r.cString()).toBe("");
  });
});

describe("buildMailDelete", () => {
  test("writes mailbox guid, mail id, and template id 0", () => {
    const body = buildMailDelete(50n, 42);
    const r = new PacketReader(body);
    expect(r.uint64LE()).toBe(50n);
    expect(r.uint32LE()).toBe(42);
    expect(r.uint32LE()).toBe(0);
    expect(r.remaining).toBe(0);
  });
});

describe("buildMailMarkAsRead", () => {
  test("writes mailbox guid and mail id", () => {
    const body = buildMailMarkAsRead(50n, 7);
    const r = new PacketReader(body);
    expect(r.uint64LE()).toBe(50n);
    expect(r.uint32LE()).toBe(7);
    expect(r.remaining).toBe(0);
  });
});

function writePlayerMail(
  w: PacketWriter,
  opts: {
    messageId: number;
    senderGuid: bigint;
    subject: string;
    body: string;
    flags?: number;
    expirationTime?: number;
    money?: number;
    itemCount?: number;
  },
) {
  const sizePos = w.offset;
  w.uint16LE(0);
  const startPos = w.offset;
  w.uint32LE(opts.messageId);
  w.uint8(MailMessageType.NORMAL);
  w.uint64LE(opts.senderGuid);
  w.uint32LE(0);
  w.uint32LE(0);
  w.uint32LE(41);
  w.uint32LE(opts.money ?? 0);
  w.uint32LE(opts.flags ?? MailCheckMask.HAS_BODY);
  w.floatLE(opts.expirationTime ?? 1.0);
  w.uint32LE(0);
  w.cString(opts.subject);
  w.cString(opts.body);
  w.uint8(opts.itemCount ?? 0);
  const endPos = w.offset;
  const buf = w.finish();
  const view = new DataView(buf.buffer, buf.byteOffset, buf.byteLength);
  view.setUint16(sizePos, endPos - startPos, true);
  return new Uint8Array(buf);
}

