export function handleShowMailbox(conn: WorldConn, r: PacketReader): void {
  conn.mailboxGuid = parseShowMailbox(r);
  conn.onMessage?.({
    type: ChatType.SYSTEM,
    sender: "",
    message: "Mailbox opened.",
