592→          conn.lastChatMode = { type: "guild" };
593→          sendPacket(
594→            conn,
595→            GameOpcode.CMSG_MESSAGE_CHAT,
596→            buildChatMessage(ChatType.GUILD, lang, message),
597→          );
598→        },
599→        sendParty(message) {
600→          conn.lastChatMode = { type: "party" };
601→          sendPacket(
602→            conn,
603→            GameOpcode.CMSG_MESSAGE_CHAT,
604→            buildChatMessage(ChatType.PARTY, lang, message),
605→          );
606→        },
607→        sendRaid(message) {
608→          conn.lastChatMode = { type: "raid" };
609→          sendPacket(
610→            conn,
611→            GameOpcode.CMSG_MESSAGE_CHAT,
