import { GuildStore, type GuildRoster, type GuildEvent } from "wow/guild-store";
import {
  buildGetMailList,
  buildSendMail,
  buildMailDelete,
  buildMailMarkAsRead,
  type MailEntry,
} from "wow/protocol/mail";
